import React, { useEffect, useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Login from './views/Login';
import Dashboard from './views/Dashboard';
import CreateDocument from './views/CreateDocument';
import DocumentDetail from './views/DocumentDetail';
import AdminUsers from './views/AdminUsers';
import AdminAssignments from './views/AdminAssignments';
import AdminHierarchy from './views/AdminHierarchy'; // New Import
import AdminDatabase from './views/AdminDatabase';
import Buffer from './views/Buffer';
import WorkList from './views/WorkList';
import Profile from './views/Profile';
import { UserRole } from './types'; 
import { logoutUser } from './services/firebaseAuthService'; 
import { useAuthStatus } from './hooks/useAuthStatus'; 
import { RefreshCw } from 'lucide-react';

const App: React.FC = () => {
    const { user, cargando } = useAuthStatus(); 
    const [longLoading, setLongLoading] = useState(false);

    // Safety timeout for loading screen stuck state
    useEffect(() => {
        let timer: NodeJS.Timeout;
        if (cargando) {
            timer = setTimeout(() => setLongLoading(true), 4000); // 4 seconds timeout
        } else {
            setLongLoading(false);
        }
        return () => clearTimeout(timer);
    }, [cargando]);

    const handleLogout = async () => {
        await logoutUser(); 
        window.location.reload();
    };

    if (cargando) {
        return (
            <div className="flex flex-col h-screen items-center justify-center bg-slate-50 gap-4">
                <div className="flex items-center gap-2 text-indigo-600 font-semibold animate-pulse">
                    <RefreshCw className="animate-spin" />
                    Cargando aplicación...
                </div>
                {longLoading && (
                    <div className="text-center animate-fadeIn">
                        <p className="text-slate-400 text-sm mb-3">Esto está tardando más de lo normal.</p>
                        <button 
                            onClick={handleLogout}
                            className="px-4 py-2 bg-white border border-slate-300 rounded-lg text-sm text-slate-600 hover:bg-slate-100 shadow-sm"
                        >
                            Forzar Cierre de Sesión
                        </button>
                    </div>
                )}
            </div>
        );
    }

    return (
        <HashRouter>
            <Routes>
                <Route 
                    path="/login" 
                    element={!user ? <Login /> : <Navigate to="/" />} 
                />

                <Route
                    path="*"
                    element={
                        user ? (
                            <Layout user={user} onLogout={handleLogout}>
                                <Routes>
                                    <Route path="/" element={<Dashboard user={user} />} />

                                    <Route path="/inbox" element={<Buffer user={user} />} />
                                    <Route path="/worklist" element={<WorkList user={user} />} />
                                    <Route path="/new" element={<CreateDocument user={user} />} />
                                    <Route path="/doc/:id" element={<DocumentDetail user={user} />} />

                                    <Route path="/profile" element={<Profile user={user} onUpdate={() => window.location.reload()} />} /> 

                                    {/* Rutas de Administración */}
                                    <Route 
                                        path="/admin/users" 
                                        element={user.role === UserRole.ADMIN ? <AdminUsers /> : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/assignments" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) ? <AdminAssignments user={user} /> : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/hierarchy" 
                                        element={user.role === UserRole.ADMIN ? <AdminHierarchy /> : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/database" 
                                        element={user.role === UserRole.ADMIN ? <AdminDatabase /> : <Navigate to="/" />} 
                                    />
                                    <Route path="*" element={<Navigate to="/" />} />
                                </Routes>
                            </Layout>
                        ) : (
                            <Navigate to="/login" />
                        )
                    }
                />
            </Routes>
        </HashRouter>
    );
};

export default App;

import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/firebaseAuthService'; 
import { Lock, User, Key, AlertCircle, TrendingUp, Mail, UserPlus, LogIn, Info } from 'lucide-react'; 
import { useNavigate } from 'react-router-dom'; 
import { auth } from '../services/firebaseConfig'; 
import { GoogleAuthProvider, signInWithPopup, UserCredential } from 'firebase/auth'; 

const Login: React.FC = () => {
    const [isRegistering, setIsRegistering] = useState(false);
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setLoading(true);
        try {
            if (isRegistering) {
                if (!name) throw new Error("El nombre es obligatorio para registrarse.");
                await registerUser(email, password, name);
                // El hook useAuthStatus detectará el nuevo usuario y creará el perfil en DB
                navigate('/');
            } else {
                await loginUser(email, password); 
                navigate('/'); 
            }
        } catch (err: any) {
            console.error(err);
            let mensajeError = 'Error de autenticación.';
            const errorCode = err.code;
            const errorMessage = err.message || '';

            // Manejo actualizado para el error de credenciales unificado de Firebase
            if (errorCode === 'auth/invalid-credential' || errorMessage.includes('invalid-credential')) {
                mensajeError = isRegistering 
                    ? 'Error al crear cuenta. Intente con otro correo.'
                    : 'Correo no registrado o contraseña incorrecta. Si es nuevo, seleccione "Crear Cuenta".';
            } else if (errorCode === 'auth/user-not-found' || errorCode === 'auth/wrong-password') {
                mensajeError = 'Usuario o contraseña incorrectos.';
            } else if (errorCode === 'auth/email-already-in-use') {
                mensajeError = 'Este correo electrónico ya está registrado. Intente iniciar sesión.';
            } else if (errorCode === 'auth/weak-password') {
                mensajeError = 'La contraseña debe tener al menos 6 caracteres.';
            } else if (errorCode === 'auth/too-many-requests') {
                mensajeError = 'Demasiados intentos fallidos. Intente más tarde.';
            } else if (err.message) {
                mensajeError = err.message;
            }
            setError(mensajeError);
            setLoading(false);
        }
    };

    const handleGoogleSignIn = async () => {
        setError('');
        setLoading(true);
        try {
            const provider = new GoogleAuthProvider();
            await signInWithPopup(auth, provider);
            navigate('/');
        } catch (err: any) {
            console.error(err);
            if (err.code === 'auth/popup-closed-by-user') {
                setError("Inicio de sesión cancelado.");
            } else {
                setError("Error al iniciar sesión con Google.");
            }
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-100 font-sans p-4">
            <div className="bg-white p-8 rounded-xl shadow-lg w-full max-w-md border border-slate-200">
                <div className="text-center mb-6">
                    <h1 className="text-3xl font-bold text-slate-900">SGD</h1>
                    <p className="text-slate-500 mt-2">Sistema de Gestión Documental</p>
                </div>

                <div className="mb-6 p-3 bg-indigo-50 border border-indigo-100 rounded-lg text-xs text-indigo-800 flex items-start gap-2">
                    <Info size={16} className="flex-shrink-0 mt-0.5" />
                    <p>
                        <strong>Objetivo:</strong> Crear una plataforma web mobile-first que permita gestionar documentos institucionales con flujos de aprobación y versionamiento formal.
                    </p>
                </div>

                <div className="flex justify-center mb-6 bg-slate-100 p-1 rounded-lg">
                    <button 
                        onClick={() => { setIsRegistering(false); setError(''); }}
                        className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${!isRegistering ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        Iniciar Sesión
                    </button>
                    <button 
                        onClick={() => { setIsRegistering(true); setError(''); }}
                        className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${isRegistering ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        Crear Cuenta
                    </button>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {isRegistering && (
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Nombre Completo</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <User size={18} className="text-slate-400" />
                                </div>
                                <input
                                    type="text"
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    className="block w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-colors"
                                    placeholder="Ej: Juan Pérez"
                                    required={isRegistering}
                                />
                            </div>
                        </div>
                    )}

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Correo Electrónico</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <Mail size={18} className="text-slate-400" />
                            </div>
                            <input
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                className="block w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-colors"
                                placeholder={isRegistering ? "admin@empresa.com" : "usuario@empresa.com"}
                                required
                            />
                        </div>
                         {isRegistering && (
                            <p className="text-[10px] text-slate-400 mt-1">Tip: Usa un correo que empiece con 'admin' para obtener permisos totales.</p>
                        )}
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Contraseña</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <Lock size={18} className="text-slate-400" />
                            </div>
                            <input
                                type="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                className="block w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-colors"
                                placeholder="••••••••"
                                required
                            />
                        </div>
                    </div>

                    {error && (
                        <div className="flex items-center gap-2 text-sm text-red-600 bg-red-50 p-3 rounded-lg border border-red-100 animate-fadeIn">
                            <AlertCircle size={16} className="flex-shrink-0" />
                            <span>{error}</span>
                        </div>
                    )}

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full bg-indigo-600 text-white py-2.5 rounded-lg hover:bg-indigo-700 transition-colors shadow-md font-medium disabled:opacity-70 flex items-center justify-center gap-2"
                    >
                        {loading ? 'Procesando...' : isRegistering ? (
                            <><UserPlus size={18} /> Registrarse</>
                        ) : (
                            <><LogIn size={18} /> Iniciar Sesión</>
                        )}
                    </button>

                    <div className="relative flex items-center justify-center py-2">
                        <div className="flex-grow border-t border-slate-200"></div>
                        <span className="flex-shrink mx-4 text-slate-400 text-xs uppercase font-semibold">O continuar con</span>
                        <div className="flex-grow border-t border-slate-200"></div>
                    </div>

                    <button
                        type="button"
                        onClick={handleGoogleSignIn}
                        disabled={loading}
                        className="w-full bg-white text-slate-700 border border-slate-300 py-2.5 rounded-lg hover:bg-slate-50 transition-colors font-medium disabled:opacity-70 flex items-center justify-center gap-2"
                    >
                        <TrendingUp size={18} className="text-red-500" /> Google
                    </button>

                </form>
            </div>
        </div>
    );
};

export default Login;

export enum UserRole {
  ADMIN = 'ADMIN',
  COORDINATOR = 'COORDINATOR',
  ANALYST = 'ANALYST',
}

export interface User {
  id: string;
  email: string;
  name: string;
  nickname?: string; // Short username
  role: UserRole;
  avatar: string;
  organization: string;
  password?: string; // Added for mock auth
}

export enum DocState {
  INITIATED = 'INITIATED',               // 0.0 - 10%
  IN_PROCESS = 'IN_PROCESS',             // 0.n - 30%
  INTERNAL_REVIEW = 'INTERNAL_REVIEW',   // v0.n - 60%
  SENT_TO_REFERENT = 'SENT_TO_REFERENT', // v1.n - 80%
  REFERENT_REVIEW = 'REFERENT_REVIEW',   // v1.n.i - N/A
  SENT_TO_CONTROL = 'SENT_TO_CONTROL',   // v1.nAR - 90%
  CONTROL_REVIEW = 'CONTROL_REVIEW',     // v1.n.iAR - N/A
  APPROVED = 'APPROVED',                 // v1.nACG - 100%
  REJECTED = 'REJECTED'                  // Workflow Loopback
}

export type DocType = 'AS IS' | 'FCE' | 'PM' | 'TO BE';

export interface DocFile {
  id: string;
  name: string;
  size: number;
  type: string;
  url: string; // Blob URL in this mock
  uploadedAt: string;
}

export interface DocHistory {
  id: string;
  documentId: string;
  userId: string;
  userName: string;
  action: string;
  previousState: DocState;
  newState: DocState;
  comment: string;
  timestamp: string;
}

// New Interface for Inbox System
export interface Notification {
  id: string;
  userId: string; // Recipient
  documentId: string;
  type: 'ASSIGNMENT' | 'APPROVAL' | 'REJECTION' | 'COMMENT';
  title: string;
  message: string;
  isRead: boolean;
  timestamp: string;
  actorName: string; // Who triggered it
}

export interface Document {
  id: string;
  title: string;
  description: string;

  // Hierarchy Metadata
  project?: string;
  macroprocess?: string;
  process?: string;
  microprocess?: string;
  docType?: DocType; // New field

  authorId: string;
  authorName: string;

  assignedTo?: string; // Legacy/Primary Display
  assignees: string[]; // Multi-user assignment support
  assignedByName?: string; // Name of Admin who assigned

  state: DocState;
  version: string;
  progress: number;
  hasPendingRequest?: boolean; // Flag for Buffer visibility

  files: DocFile[];
  createdAt: string;
  updatedAt: string;
}

// Assignment Module Types
export interface AssignmentLog {
  id: string;
  documentId: string;
  analystId: string;
  assignedBy: string; // Admin ID
  assignedAt: string;
  reason?: string;
}

export interface AnalystWorkload {
  analyst: User;
  activeDocs: number;
  completedDocs: number; // Approved
  lastAssignment?: string;
}

export interface ParsedFilenameResult {
  valido: boolean;
  proyecto?: 'HPC' | 'HSR';
  microproceso?: string;
  tipo?: string;
  nomenclatura?: string;
  estado?: string;
  porcentaje?: number;
  explicacion?: string;
  errores: string[];
}

// Hierarchy Types for strict typing
export interface UserHierarchy {
  [project: string]: {
    [macro: string]: {
      [process: string]: string[]; // Array of microprocess names
    };
  };
}

export interface ProcessNode {
  name: string;
  docId: string; // This acts as the matrix ID
  assignees: string[];
  requiredTypes: DocType[]; // List of types defined in initial load
  active?: boolean; // Soft Delete support
}

export interface FullHierarchy {
  [project: string]: {
    [macro: string]: {
      [process: string]: ProcessNode[]; // Array of nodes with metadata
    };
  };
}

// Response for mock API
export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
}

