    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Document));
  },
  getById: async (id: string): Promise<Document | null> => {
    const docRef = doc(db, "documents", id);
    const docSnap = await getDoc(docRef);
    if (docSnap.exists()) return { id: docSnap.id, ...docSnap.data() } as Document;
    return null;
  },
  create: async (title: string, description: string, author: User, initialState?: DocState, initialVersion?: string, initialProgress?: number, file?: File, hierarchy?: any): Promise<Document> => {
    const state = initialState || DocState.INITIATED;
    const isSubmission = state === DocState.INTERNAL_REVIEW || state === DocState.SENT_TO_REFERENT || state === DocState.SENT_TO_CONTROL;
    const newDocData: Omit<Document, 'id'> = {
      title, description, authorId: author.id, authorName: author.name,
      assignedTo: author.id, assignees: [author.id],
      state, version: initialVersion || '0.0', progress: initialProgress || 10,
      hasPendingRequest: isSubmission,
      files: [], createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(),
      project: hierarchy?.project, macroprocess: hierarchy?.macro, process: hierarchy?.process, microprocess: hierarchy?.micro, docType: hierarchy?.docType
    };
    const safeDocData = JSON.parse(JSON.stringify(newDocData));
    const docRef = await addDoc(collection(db, "documents"), safeDocData);
    const docId = docRef.id;
    if (file) {
       const newFile: DocFile = {
           id: `file-${Date.now()}`, name: file.name, size: file.size, type: file.type,
           url: '#', uploadedAt: new Date().toISOString()
       };
       await updateDoc(docRef, { files: [newFile] });
       newDocData.files = [newFile];
    }
    await HistoryService.log(docId, author, 'Creación', state, state, 'Documento creado (Registro de versión).');
    await HistoryService.log(docId, author, 'Asignación', state, state, `Asignado a: ${author.name}`);
    return { id: docId, ...newDocData } as Document;
  },
  uploadFile: async (docId: string, file: File, user: User): Promise<DocFile> => {
      const docRef = doc(db, "documents", docId);
      const docSnap = await getDoc(docRef);
      if(!docSnap.exists()) throw new Error("Doc not found");
      const currentDoc = docSnap.data() as Document;
      const newFile: DocFile = {
          id: `file-${Date.now()}`, name: file.name, size: file.size, type: file.type,
          url: '#', uploadedAt: new Date().toISOString()
      };
      const updatedFiles = [...(currentDoc.files || []), newFile];
      const updates: any = { files: updatedFiles, updatedAt: new Date().toISOString() };
      const parts = file.name.replace(/\.[^/.]+$/, "").split(' - ');
      if (parts.length >= 4) {
          const newVersion = parts[parts.length - 1];
          const { state, progress } = determineStateFromVersion(newVersion);
          updates.version = newVersion;
          updates.state = state;
          updates.progress = progress;
      }
      await updateDoc(docRef, updates);
      return newFile;
  },
  delete: async (id: string) => {
      await deleteDoc(doc(db, "documents", id));
  },
  transitionState: async (docId: string, user: User, action: 'ADVANCE' | 'REJECT' | 'APPROVE' | 'REQUEST_APPROVAL' | 'COMMENT', comment: string, file?: File, customVersion?: string): Promise<void> => {
      const docRef = doc(db, "documents", docId);
      const docSnap = await getDoc(docRef);
      if(!docSnap.exists()) throw new Error("Doc not found");
      const currentDoc = docSnap.data() as Document;
      let newState = currentDoc.state;
      let newVersion = currentDoc.version;
      let hasPending = currentDoc.hasPendingRequest;
      let updatedFiles = [...currentDoc.files];
      if (file) {
          updatedFiles.push({
              id: `file-${Date.now()}`, name: file.name, size: file.size, type: file.type,
              url: '#', uploadedAt: new Date().toISOString()
          });
      }
      if (customVersion) {
        newVersion = customVersion;
        if (action === 'APPROVE') {
            const { state } = determineStateFromVersion(customVersion);
            newState = state;
        }
      }
      switch (action) {
        case 'REQUEST_APPROVAL':
            hasPending = true;
            if (currentDoc.state === DocState.IN_PROCESS || currentDoc.state === DocState.INITIATED || currentDoc.state === DocState.REJECTED || currentDoc.state === DocState.NOT_STARTED) {
                newState = DocState.INTERNAL_REVIEW;
            }
            break;
        case 'APPROVE': hasPending = false; break;
        case 'REJECT': hasPending = false; newState = DocState.REJECTED; comment = `RECHAZADO: ${comment}`; break;
        case 'ADVANCE': hasPending = false; if (currentDoc.state === DocState.REJECTED) newState = DocState.IN_PROCESS; break;
        case 'COMMENT': comment = `OBSERVACIÓN: ${comment}`; break;
      }
      const progress = STATE_CONFIG[newState]?.progress || currentDoc.progress;
      await updateDoc(docRef, {
          state: newState, version: newVersion, hasPendingRequest: hasPending,
          files: updatedFiles, progress, updatedAt: new Date().toISOString()
      });
      const actionLabel = action === 'COMMENT' ? 'Observación' : action;
      await HistoryService.log(docId, user, actionLabel, currentDoc.state, newState, comment);

      if (action === 'APPROVE' || action === 'REJECT') {
          const targetIds = currentDoc.assignees || [currentDoc.authorId];
          const type = action === 'APPROVE' ? 'APPROVAL' : 'REJECTION';
          const title = action === 'APPROVE' ? 'Documento Aprobado' : 'Documento Rechazado';
          targetIds.forEach(targetId => {
              if (targetId !== user.id) {
                  NotificationService.create(targetId, docId, type, title, `${currentDoc.title}: ${comment}`, user.name);
              }
          });
      }
      if (action === 'COMMENT') {
           if (user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) {
               const targetIds = currentDoc.assignees || [currentDoc.authorId];
               targetIds.forEach(targetId => {
                  if (targetId !== user.id) NotificationService.create(targetId, docId, 'COMMENT', 'Nueva Observación', `${currentDoc.title}: ${comment}`, user.name);
               });
           } else {
               const allUsers = await UserService.getAll();
               const coords = allUsers.filter(u => u.role === UserRole.COORDINATOR);
               coords.forEach(c => NotificationService.create(c.id, docId, 'COMMENT', 'Comentario de Analista', `${currentDoc.title}: ${comment}`, user.name));
           }
      }
      if (action === 'REQUEST_APPROVAL') {
           const allUsers = await UserService.getAll();
           const coords = allUsers.filter(u => u.role === UserRole.COORDINATOR);
           coords.forEach(c => NotificationService.create(c.id, docId, 'COMMENT', 'Solicitud de Aprobación', `${currentDoc.title} requiere revisión.`, user.name));
      }
  }
};

export const HierarchyService = {
  getFullHierarchy: async (): Promise<FullHierarchy> => {
    const q = query(collection(db, "process_matrix"));
    const snapshot = await getDocs(q);
    const hierarchy: FullHierarchy = {};
    snapshot.docs.forEach(docSnap => {
        const data = docSnap.data();
        const project = data.project || 'Sin Proyecto';
        const macro = data.macro || 'General';
        const process = data.process || 'General';
        const microName = data.name || data.micro || data.microprocess || 'Sin Nombre';

        // Active Check: default to true if undefined
        const isActive = data.active !== false; 

        if (!hierarchy[project]) hierarchy[project] = {};
        if (!hierarchy[project][macro]) hierarchy[project][macro] = {};
        if (!hierarchy[project][macro][process]) hierarchy[project][macro][process] = [];

        hierarchy[project][macro][process].push({
            name: String(microName), 
            docId: docSnap.id, 
            assignees: data.assignees || [], 
            requiredTypes: data.requiredTypes || [],
            active: isActive
        });
    });
    Object.keys(hierarchy).forEach(p => {
        Object.keys(hierarchy[p]).forEach(m => {
            Object.keys(hierarchy[p][m]).forEach(proc => {
                hierarchy[p][m][proc].sort((a, b) => {
                    const nameA = a.name || ''; const nameB = b.name || '';
                    return nameA.localeCompare(nameB);
                });
            });
        });
    });
    return hierarchy;
  },

  getUserHierarchy: async (userId: string): Promise<UserHierarchy> => {
    const q = query(collection(db, "process_matrix"), where("assignees", "array-contains", userId));
    const snapshot = await getDocs(q);
    const hierarchy: UserHierarchy = {};
    snapshot.docs.forEach(docSnap => {
        const data = docSnap.data();

        // Filter out inactive items for normal users
        if (data.active === false) return;

        const project = data.project || 'Sin Proyecto';
        const macro = data.macro || 'General';
        const process = data.process || 'General';
        const microName = data.name || data.micro || data.microprocess || 'Sin Nombre';
        if (!hierarchy[project]) hierarchy[project] = {};
        if (!hierarchy[project][macro]) hierarchy[project][macro] = {};
        if (!hierarchy[project][macro][process]) hierarchy[project][macro][process] = [];
        hierarchy[project][macro][process].push(String(microName));
    });
    return hierarchy;
  },

  getRequiredTypesMap: async (): Promise<Record<string, DocType[]>> => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const map: Record<string, DocType[]> = {};
      snapshot.docs.forEach(docSnap => {
          const data = docSnap.data();
          if (data.active === false) return; // Skip requirements for inactive processes
          const microName = data.name || data.micro || data.microprocess || 'Sin Nombre';
          const key = `${data.project}|${microName}`;
          map[key] = data.requiredTypes || [];
      });
      return map;
  },

  seedDefaults: async () => {
      const batch = writeBatch(db);
      for (const row of REQUIRED_DOCS_MATRIX) {
          const [proj, micro, asis, fce, pm, tobe] = row;
          const id = generateMatrixId(proj as string, micro as string);
          const docRef = doc(db, "process_matrix", id);
          const requiredTypes: DocType[] = [];
          if (asis) requiredTypes.push('AS IS');
          if (fce) requiredTypes.push('FCE');
          if (pm) requiredTypes.push('PM');
          if (tobe) requiredTypes.push('TO BE');
          const snap = await getDoc(docRef);
          if (!snap.exists()) {
              batch.set(docRef, {
                  project: proj, macro: 'Macroproceso General', process: 'Proceso General',
                  name: micro, requiredTypes, assignees: [], active: true
              });
          }
      }
      await batch.commit();
  },

  addMicroprocess: async (project: string, macro: string, process: string, name: string, assignees: string[], requiredTypes: DocType[]) => {
      const id = generateMatrixId(project, name);
      const docRef = doc(db, "process_matrix", id);
      await setDoc(docRef, { project, macro, process, name, assignees, requiredTypes, active: true });
  },

  // NEW: Toggle Active Status (Soft Delete)
  toggleProcessStatus: async (id: string, currentActiveStatus: boolean) => {
      if (!id || !id.trim()) throw new Error("ID no válido");
      const docRef = doc(db, "process_matrix", id.trim());
      await updateDoc(docRef, { active: !currentActiveStatus });
  },

  // Deprecated - replaced by soft delete, but kept for legacy cleanup if needed
  deleteMicroprocess: async (id: string) => {
      if (!id || !id.trim()) throw new Error("ID no válido");
      await deleteDoc(doc(db, "process_matrix", id.trim()));
  },

  updateMatrixAssignment: async (id: string, assignees: string[], updatedBy: string) => {
      const docRef = doc(db, "process_matrix", id);
      await updateDoc(docRef, { assignees });
  },

  toggleRequiredType: async (id: string, type: DocType) => {
      const docRef = doc(db, "process_matrix", id);
      const snap = await getDoc(docRef);
      if (snap.exists()) {
          const current = snap.data().requiredTypes || [];
          let updated = [];
          if (current.includes(type)) updated = current.filter((t: string) => t !== type);
          else updated = [...current, type];
          await updateDoc(docRef, { requiredTypes: updated });
      }
  },

  updateHierarchyNode: async (
      level: 'PROJECT' | 'MACRO' | 'PROCESS', 
      oldValue: string, 
      newValue: string, 
      parentContext?: { project?: string, macro?: string }
  ) => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      let count = 0;

      snapshot.docs.forEach(docSnap => {
          const data = docSnap.data();
          let shouldUpdate = false;
          const updates: any = {};

          if (level === 'PROJECT') {
              if (data.project === oldValue) {
                  updates.project = newValue;
                  shouldUpdate = true;
              }
          } else if (level === 'MACRO') {
              if (data.project === parentContext?.project && data.macro === oldValue) {
                  updates.macro = newValue;
                  shouldUpdate = true;
              }
          } else if (level === 'PROCESS') {
              if (data.project === parentContext?.project && data.macro === parentContext?.macro && data.process === oldValue) {
                  updates.process = newValue;
                  shouldUpdate = true;
              }
          }

          if (shouldUpdate) {
              batch.update(docSnap.ref, updates);
              count++;
          }
      });

      if (count > 0) await batch.commit();
      console.log(`Updated ${count} records for rename operation.`);
  },

  // NEW: Cascading Delete for Hierarchy Management (Still performs hard delete for structure changes, but could be soft in future)
  deleteHierarchyNode: async (
      level: 'PROJECT' | 'MACRO' | 'PROCESS',
      value: string,
      parentContext?: { project?: string, macro?: string }
  ) => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      let count = 0;

      snapshot.docs.forEach(docSnap => {
          const data = docSnap.data();
          let shouldDelete = false;

          if (level === 'PROJECT') {
              if (data.project === value) shouldDelete = true;
          } else if (level === 'MACRO') {
              if (data.project === parentContext?.project && data.macro === value) shouldDelete = true;
          } else if (level === 'PROCESS') {
              if (data.project === parentContext?.project && data.macro === parentContext?.macro && data.process === value) shouldDelete = true;
          }

          if (shouldDelete) {
              batch.delete(docSnap.ref);
              count++;
          }
      });

      if (count > 0) await batch.commit();
      console.log(`Deleted ${count} records for cascade delete operation.`);
  }
};

export const DatabaseService = {
  exportData: async (): Promise<string> => {
      const data: any = { users: [], documents: [], history: [], notifications: [], process_matrix: [] };
      const collections = ['users', 'documents', 'history', 'notifications', 'process_matrix'];
      for (const colName of collections) {
          const q = query(collection(db, colName));
          const snapshot = await getDocs(q);
          data[colName] = snapshot.docs.map(d => ({ _id: d.id, ...d.data() }));
      }
      return JSON.stringify(data, null, 2);
  },
  importData: async (jsonContent: string) => {
      const data = JSON.parse(jsonContent);
      const collections = ['users', 'documents', 'history', 'notifications', 'process_matrix'];
      for (const colName of collections) await deleteCollectionInBatches(colName);
      for (const colName of collections) {
          if (data[colName]) {
              const batchSize = 400;
              let batch = writeBatch(db);
              let count = 0;
              for (const item of data[colName]) {
                  const { _id, ...rest } = item;
                  const docRef = doc(db, colName, _id);
                  batch.set(docRef, rest);
                  count++;
                  if (count >= batchSize) { await batch.commit(); batch = writeBatch(db); count = 0; }
              }
              if (count > 0) await batch.commit();
          }
      }
  },
  fullSystemResetAndImport: async (rulesCsv: string, historyCsv: string | null, onProgress: (percent: number, status: string) => void) => {
      onProgress(5, "Limpiando base de datos...");
      await deleteCollectionInBatches('documents');
      await deleteCollectionInBatches('history');
      await deleteCollectionInBatches('process_matrix');
      await deleteCollectionInBatches('notifications');

      const users = await UserService.getAll();

      // PHASE 1: Parse History to Memory Map (12 Columns Strict Format)
      // Structure: Key (Proj|Micro) -> { 'AS IS': {ver, date}, 'FCE': ... }
      type HistoryInfo = { version: string, date: string, state: DocState, progress: number };
      const historyMap = new Map<string, Record<string, HistoryInfo>>();

      if (historyCsv) {
          onProgress(15, "Analizando Histórico de Documentos...");
          const hLines = historyCsv.split('\n');
          for (let i = 1; i < hLines.length; i++) {
              const line = hLines[i].trim();
              if (!line) continue;
              const separator = line.includes(';') ? ';' : ',';
              const cols = line.split(separator);

              // NEW FORMAT (12 Cols):
              // 0: PROYECTO
              // 1: MACROPROCESO
              // 2: PROCESO
              // 3: MICROPROCESO
              // 4: Ver AS IS | 5: Fecha AS IS
              // 6: Ver FCE   | 7: Fecha FCE
              // 8: Ver PM    | 9: Fecha PM
              // 10: Ver TO BE| 11: Fecha TO BE

              if (cols.length < 12) continue; 

              const project = normalizeHeader(cols[0]);
              const micro = normalizeHeader(cols[3]);
              const key = `${project}|${micro}`;

              const docTypesMap: { type: DocType, vIdx: number, dIdx: number }[] = [
                  { type: 'AS IS', vIdx: 4, dIdx: 5 },
                  { type: 'FCE', vIdx: 6, dIdx: 7 },
                  { type: 'PM', vIdx: 8, dIdx: 9 },
                  { type: 'TO BE', vIdx: 10, dIdx: 11 },
              ];

              const entry: Record<string, HistoryInfo> = {};
              let hasData = false;

              docTypesMap.forEach(dt => {
                   const ver = cols[dt.vIdx]?.trim();
                   const dateStr = cols[dt.dIdx]?.trim();
                   // STRICT: v must exist and not be empty, '-' or '0.0' unless it matches specific states
                   // We defer to determineStateFromVersion for strictness
                   if (ver && ver !== '-' && ver !== '') {
                       const { state, progress } = determineStateFromVersion(ver);
                       entry[dt.type] = {
                           version: ver,
                           date: parseDateString(dateStr),
                           state, 
                           progress
                       };
                       hasData = true;
                   }
              });

              if (hasData) {
                  historyMap.set(key, entry);
              }
          }
      }

      onProgress(30, "Construyendo Matriz y Generando Documentos Específicos...");

      const lines = rulesCsv.split('\n');
      let batch = writeBatch(db); 
      let ops = 0;
      let createdCount = 0;
      let historyMatchedCount = 0;
      const BATCH_LIMIT = 400; 

      for (let i = 1; i < lines.length; i++) {
           const line = lines[i].trim();
           if (!line) continue;
           const separator = line.includes(';') ? ';' : ',';
           const cols = line.split(separator);

           if (cols.length < 9) continue;

           // NEW RULES STRUCTURE (9 Cols):
           // 0: MacroProceso
           // 1: Proceso
           // 2: MicroProceso
           // 3: Analista
           // 4: PROYECTO
           // 5: AS IS (Flag 0/1)
           // 6: FCE (Flag 0/1)
           // 7: PM (Flag 0/1)
           // 8: TO BE (Flag 0/1)

           const macro = cols[0]?.trim() || 'Macroproceso General';
           const process = cols[1]?.trim() || 'Proceso General';
           const micro = cols[2]?.trim();
           const responsableRaw = cols[3]?.trim();
           const project = cols[4]?.trim();

           if (!project || !micro) continue;

           let assignees = findUserIdsFromCSV(users, responsableRaw);

           let requiredTypes: DocType[] = [];
           const asis = cols[5]?.trim() === '1';
           const fce = cols[6]?.trim() === '1';
           const pm = cols[7]?.trim() === '1';
           const tobe = cols[8]?.trim() === '1';

           if (asis) requiredTypes.push('AS IS');
           if (fce) requiredTypes.push('FCE');
           if (pm) requiredTypes.push('PM');
           if (tobe) requiredTypes.push('TO BE');

           // 1. Create Matrix Entry (Deterministic ID)
           const matrixId = generateMatrixId(project, micro);
           const matrixRef = doc(db, "process_matrix", matrixId);

           batch.set(matrixRef, { 
               project, macro, process, name: micro, 
               assignees, requiredTypes, active: true 
           });
           ops++;

           // 2. Create Specific Documents based on History OR Requirement
           const lookupKey = `${normalizeHeader(project)}|${normalizeHeader(micro)}`;
           const historyRecord = historyMap.get(lookupKey);

           // Determine which types to create:
           // Union of Required Types AND Types present in history
           const typesToCreate = new Set<DocType>(requiredTypes);
           if (historyRecord) {
               Object.keys(historyRecord).forEach(k => typesToCreate.add(k as DocType));
               historyMatchedCount++; // Just counting hit on the row
           }

           for (const type of typesToCreate) {
                const histData = historyRecord ? historyRecord[type] : null;

                let state, version, progress, date;

                if (histData) {
                    // CASE A: History exists
                    state = histData.state;
                    version = histData.version;
                    progress = histData.progress;
                    date = histData.date;
                } else {
                    // CASE B: Required but NO History found -> NOT STARTED
                    state = DocState.NOT_STARTED;
                    version = '-';
                    progress = 0;
                    date = ''; // Empty string indicates no activity
                }

                // Use DETERMINISTIC ID to prevent duplicates if rules are re-run or duplicated in CSV
                const docId = generateDocumentId(project, micro, type);
                const newDocRef = doc(db, "documents", docId);

                const docData: Omit<Document, 'id'> = {
                    title: `${micro} - ${type}`, // Specific Name
                    description: histData ? `Migrado desde Histórico (${version})` : 'Documento Requerido (Pendiente)',
                    authorId: assignees[0] || 'admin',
                    authorName: 'Sistema',
                    assignedTo: assignees[0] || 'admin',
                    assignees: assignees.length > 0 ? assignees : ['admin'],
                    state: state,
                    version: version,
                    progress: progress,
                    hasPendingRequest: false,
                    files: [], 
                    createdAt: date || new Date().toISOString(), 
                    updatedAt: date || '', // Empty if not started
                    project, macroprocess: macro, process, microprocess: micro, 
                    docType: type // EXPLICIT TYPE
                };

                batch.set(newDocRef, JSON.parse(JSON.stringify(docData)));
                ops++;
                createdCount++;
           }

           if (ops >= BATCH_LIMIT) {
               await batch.commit();
               batch = writeBatch(db);
               ops = 0;
           }
      }
      if (ops > 0) await batch.commit();

      onProgress(100, "Carga Completa.");
      return { created: createdCount, historyMatched: historyMatchedCount, errors: [] };
  }
};

import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { DocumentService, HierarchyService, UserService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { Plus, FileText, Clock, CheckCircle, AlertTriangle, Filter, Trash2, Users, Search, X, Calendar, Inbox, ArrowRight, Activity, BookOpen, UserCheck, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface DashboardProps {
  user: User;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'REQUIRED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [docs, setDocs] = useState<Document[]>([]);
  const [requiredMap, setRequiredMap] = useState<Record<string, DocType[]>>({});
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  // Filter States
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState('');
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Quick Filter State (Stat Cards)
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'updatedAt',
    direction: 'desc' // Default: Newest first
  });

  useEffect(() => {
    loadData();
  }, []);

  // Helper to compare versions robustly
  const isVersionNewer = (v1: string, v2: string): boolean => {
      if (!v1) return false;
      if (!v2) return true;
      if (v1 === '-') return false; // Not Started is always older

      // Clean versions (remove 'v', 'AR', 'ACG')
      const cleanV1 = v1.replace(/[^0-9.]/g, '');
      const cleanV2 = v2.replace(/[^0-9.]/g, '');

      const parts1 = cleanV1.split('.').map(Number);
      const parts2 = cleanV2.split('.').map(Number);

      for (let i = 0; i < Math.max(parts1.length, parts2.length); i++) {
          const num1 = parts1[i] || 0;
          const num2 = parts2[i] || 0;
          if (num1 > num2) return true;
          if (num1 < num2) return false;
      }

      // If numbers are equal, check specific suffixes for priority
      // Priority: ACG > AR > (none)
      const weight1 = v1.includes('ACG') ? 3 : v1.includes('AR') ? 2 : 1;
      const weight2 = v2.includes('ACG') ? 3 : v2.includes('AR') ? 2 : 1;

      return weight1 > weight2;
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [data, reqs, users] = await Promise.all([
            DocumentService.getAll(),
            HierarchyService.getRequiredTypesMap(),
            UserService.getAll()
        ]);

        // DEDUPLICATION LOGIC (Show only latest version)
        // Group by Project + Microprocess + DocType
        const latestDocsMap = new Map<string, Document>();

        data.forEach(doc => {
            const uniqueKey = `${doc.project || 'Gen'}|${doc.microprocess || doc.title}|${doc.docType || 'Gen'}`;
            const existing = latestDocsMap.get(uniqueKey);

            // Logic: Determine which is the "Current Active" document
            let shouldUseNew = false;

            if (!existing) {
                shouldUseNew = true;
            } else {
                const timeNew = doc.updatedAt ? new Date(doc.updatedAt).getTime() : 0;
                const timeExisting = existing.updatedAt ? new Date(existing.updatedAt).getTime() : 0;

                // 1. Primary check: Date
                if (timeNew > timeExisting) {
                    shouldUseNew = true;
                } 
                // 2. Secondary check: If dates are effectively equal (common in bulk imports), use Version
                else if (timeNew === timeExisting) {
                    if (isVersionNewer(doc.version, existing.version)) {
                        shouldUseNew = true;
                    }
                }
            }

            if (shouldUseNew) {
                latestDocsMap.set(uniqueKey, doc);
            }
        });

        const finalDocs = Array.from(latestDocsMap.values());

        setDocs(finalDocs);
        setRequiredMap(reqs);
        setAllUsers(users);
    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const handleDeleteDoc = async (id: string, e: React.MouseEvent) => {
    e.preventDefault(); // Prevent navigation
    if (!window.confirm('¿Eliminar este documento permanentemente?')) return;
    await DocumentService.delete(id);
    await loadData();
  };

  // Helper to determine if a doc is strictly required
  const isDocRequired = (doc: Document): boolean => {
      const key = `${doc.project}|${doc.microprocess}`;
      const requiredTypes = requiredMap[key];
      if (!requiredTypes) return false; 
      return doc.docType ? requiredTypes.includes(doc.docType) : false;
  };

  // Helper to get formatted assignees names (returns array of names for display filtering)
  const getAssigneesNames = (doc: Document): string[] => {
      if (!doc.assignees || doc.assignees.length === 0) return [doc.authorName]; 
      return doc.assignees
          .map(id => allUsers.find(u => u.id === id)?.name)
          .filter((name): name is string => !!name);
  };

  const handleQuickFilterClick = (type: QuickFilterType) => {
      if (quickFilter === type) {
          setQuickFilter('ALL'); // Toggle off
      } else {
          setQuickFilter(type);
          setFilterState(''); // Reset manual state dropdown to avoid conflicts
      }
  };

  const getFilteredDocs = () => {
    let filtered = docs;

    // 2. Explicit Filters
    if (filterProject) {
        filtered = filtered.filter(d => d.project === filterProject);
    }
    if (filterMacro) {
        filtered = filtered.filter(d => d.macroprocess === filterMacro);
    }
    if (filterProcess) {
        filtered = filtered.filter(d => d.process === filterProcess);
    }
    if (filterDocType) {
        filtered = filtered.filter(d => d.docType === filterDocType);
    }
    if (filterState) {
        filtered = filtered.filter(d => d.state === filterState);
    }
    if (filterAnalyst) {
        filtered = filtered.filter(d => {
            const names = getAssigneesNames(d);
            // Check if ANY of the assignees matches the filter
            return names.includes(filterAnalyst);
        });
    }

    // 3. Quick Filters (Stat Cards)
    if (quickFilter !== 'ALL') {
        // All quick filters (except ALL) imply showing "Required" docs context
        filtered = filtered.filter(d => isDocRequired(d));

        switch (quickFilter) {
            case 'IN_PROCESS':
                filtered = filtered.filter(d => 
                    d.state === DocState.NOT_STARTED || // Include Not Started in Process view as pending work
                    d.state === DocState.INITIATED || 
                    d.state === DocState.IN_PROCESS || 
                    d.state === DocState.INTERNAL_REVIEW
                );
                break;
            case 'REFERENT':
                filtered = filtered.filter(d => 
                    d.state === DocState.SENT_TO_REFERENT || 
                    d.state === DocState.REFERENT_REVIEW
                );
                break;
            case 'CONTROL':
                filtered = filtered.filter(d => 
                    d.state === DocState.SENT_TO_CONTROL || 
                    d.state === DocState.CONTROL_REVIEW
                );
                break;
            case 'FINISHED':
                filtered = filtered.filter(d => d.state === DocState.APPROVED);
                break;
            case 'REQUIRED':
                // Already filtered by isDocRequired above
                break;
        }
    }

    return filtered;
  };

  // Sorting Logic
  const handleSort = (key: SortKey) => {
      let direction: 'asc' | 'desc' = 'asc';
      if (sortConfig.key === key && sortConfig.direction === 'asc') {
          direction = 'desc';
      }
      setSortConfig({ key, direction });
  };

  const getSortedDocs = (filtered: Document[]) => {
      return [...filtered].sort((a, b) => {
          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt':
                  const timeA = a.updatedAt ? new Date(a.updatedAt).getTime() : 0;
                  const timeB = b.updatedAt ? new Date(b.updatedAt).getTime() : 0;
                  return (timeA - timeB) * modifier;
              case 'project':
                  return (a.project || '').localeCompare(b.project || '') * modifier;
              case 'microprocess':
                  const nameA = a.microprocess || a.title;
                  const nameB = b.microprocess || b.title;
                  return nameA.localeCompare(nameB) * modifier;
              case 'state':
                   return (a.progress - b.progress) * modifier;
              default:
                  return 0;
          }
      });
  };

  const filteredDocs = getFilteredDocs();
  const sortedDocs = getSortedDocs(filteredDocs);

  // Extract unique values for dropdowns from the FULL deduplicated list
  const baseDocs = docs;

  const uniqueProjects = Array.from(new Set(baseDocs.map(d => d.project).filter(Boolean))) as string[];

  const uniqueMacros = Array.from(new Set(
      baseDocs.filter(d => !filterProject || d.project === filterProject)
      .map(d => d.macroprocess).filter(Boolean)
  )) as string[];

  const uniqueProcesses = Array.from(new Set(
      baseDocs.filter(d => (!filterProject || d.project === filterProject) && (!filterMacro || d.macroprocess === filterMacro))
      .map(d => d.process).filter(Boolean)
  )) as string[];

  const uniqueDocTypes = Array.from(new Set(
      baseDocs.filter(d => 
        (!filterProject || d.project === filterProject) && 
        (!filterMacro || d.macroprocess === filterMacro) &&
        (!filterProcess || d.process === filterProcess)
      )
      .map(d => d.docType).filter(Boolean)
  )) as string[];

  // Flattened list of individual analysts
  const uniqueAnalysts = Array.from(new Set(
      baseDocs.filter(d => 
        (!filterProject || d.project === filterProject) && 
        (!filterMacro || d.macroprocess === filterMacro)
      )
      .flatMap(d => getAssigneesNames(d))
  )).sort() as string[];

  // Calculate Stats based on BASE filtered documents (ignoring quick filter for the counts themselves to stay static relative to dropdowns)
  const contextDocs = (() => {
      let d = docs;
      if (filterProject) d = d.filter(doc => doc.project === filterProject);
      if (filterMacro) d = d.filter(doc => doc.macroprocess === filterMacro);
      if (filterProcess) d = d.filter(doc => doc.process === filterProcess);
      if (filterDocType) d = d.filter(doc => doc.docType === filterDocType);
      if (filterAnalyst) d = d.filter(doc => getAssigneesNames(doc).includes(filterAnalyst));
      return d.filter(doc => isDocRequired(doc));
  })();

  const stats = {
    totalRequired: contextDocs.length,
    inProcess: contextDocs.filter(d => 
        d.state === DocState.NOT_STARTED ||
        d.state === DocState.INITIATED || 
        d.state === DocState.IN_PROCESS || 
        d.state === DocState.INTERNAL_REVIEW
    ).length,
    referent: contextDocs.filter(d => 
        d.state === DocState.SENT_TO_REFERENT || 
        d.state === DocState.REFERENT_REVIEW
    ).length,
    control: contextDocs.filter(d => 
        d.state === DocState.SENT_TO_CONTROL || 
        d.state === DocState.CONTROL_REVIEW
    ).length,
    finished: contextDocs.filter(d => d.state === DocState.APPROVED).length
  };

  const chartData = [
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control Gestión', value: stats.control, color: '#f97316' },
    { name: 'Terminados', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const clearFilters = () => {
      setFilterProject('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterDocType('');
      setFilterState('');
      setFilterAnalyst('');
      setQuickFilter('ALL');
  };

  const hasFilters = filterProject || filterMacro || filterProcess || filterDocType || filterState || filterAnalyst || quickFilter !== 'ALL';

  const SortIcon = ({ column }: { column: SortKey }) => {
      if (sortConfig.key !== column) return <ArrowUpDown size={14} className="text-slate-300 opacity-0 group-hover:opacity-100 transition-opacity" />;
      return sortConfig.direction === 'asc' 
        ? <ArrowUp size={14} className="text-indigo-600" /> 
        : <ArrowDown size={14} className="text-indigo-600" />;
  };

  // Show analyst filter for everyone now, as everyone can see everything
  const showAnalystFilter = true; 

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando dashboard...</div>;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-900">Dashboard</h1>
            <p className="text-slate-500">Vista general</p>
        </div>
        <div className="flex gap-2">
            {user.role === UserRole.ADMIN && (
                <Link to="/admin/users" className="inline-flex items-center justify-center px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors shadow-sm">
                    <Users size={18} className="mr-2" />
                    Gestionar Usuarios
                </Link>
            )}
            {user.role === UserRole.ANALYST && (
                <Link to="/new" className="inline-flex items-center justify-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm">
                    <Plus size={18} className="mr-2" />
                    Nueva Solicitud
                </Link>
            )}
        </div>
      </div>

      {/* Stats Cards - Interactive */}
      <div className="grid grid-cols-1 md:grid-cols-5 gap-3">
        <StatCard 
            title="Doc. Requeridos" 
            value={stats.totalRequired} 
            icon={BookOpen} 
            color="bg-slate-100 text-slate-600" 
            isActive={quickFilter === 'REQUIRED'}
            onClick={() => handleQuickFilterClick('REQUIRED')}
        />
        <StatCard 
            title="En Proceso" 
            value={stats.inProcess} 
            icon={Activity} 
            color="bg-blue-100 text-blue-600" 
            isActive={quickFilter === 'IN_PROCESS'}
            onClick={() => handleQuickFilterClick('IN_PROCESS')}
        />
        <StatCard 
            title="Referente" 
            value={stats.referent} 
            icon={Users} 
            color="bg-purple-100 text-purple-600" 
            isActive={quickFilter === 'REFERENT'}
            onClick={() => handleQuickFilterClick('REFERENT')}
        />
        <StatCard 
            title="Control Gestión" 
            value={stats.control} 
            icon={ShieldCheck} 
            color="bg-orange-100 text-orange-600" 
            isActive={quickFilter === 'CONTROL'}
            onClick={() => handleQuickFilterClick('CONTROL')}
        />
        <StatCard 
            title="Terminados" 
            value={stats.finished} 
            icon={CheckCircle} 
            color="bg-green-100 text-green-600" 
            isActive={quickFilter === 'FINISHED'}
            onClick={() => handleQuickFilterClick('FINISHED')}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Document List (Takes up 3 columns) */}
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">

            {/* Filter Bar */}
            <div className="p-4 border-b border-slate-100 bg-slate-50/50">
                <div className="flex items-center justify-between mb-3">
                    <h2 className="font-semibold text-slate-800 flex items-center gap-2">
                        <Filter size={18} className="text-indigo-600" />
                        Todos los Documentos
                    </h2>
                    {hasFilters && (
                        <button onClick={clearFilters} className="text-xs text-red-500 flex items-center gap-1 hover:underline">
                            <X size={14} /> Limpiar filtros
                        </button>
                    )}
                </div>

                {quickFilter !== 'ALL' && (
                    <div className="mb-3 px-3 py-2 bg-indigo-50 border border-indigo-100 rounded-lg text-sm text-indigo-700 flex items-center justify-between">
                        <span>
                            Filtrando por: <strong>
                                {quickFilter === 'REQUIRED' && 'Total Requeridos'}
                                {quickFilter === 'IN_PROCESS' && 'En Proceso'}
                                {quickFilter === 'REFERENT' && 'En Referente'}
                                {quickFilter === 'CONTROL' && 'Control de Gestión'}
                                {quickFilter === 'FINISHED' && 'Terminados'}
                            </strong>
                        </span>
                        <button onClick={() => setQuickFilter('ALL')} className="text-indigo-500 hover:text-indigo-800"><X size={16}/></button>
                    </div>
                )}

                <div className={`grid grid-cols-1 gap-3 ${showAnalystFilter ? 'md:grid-cols-6' : 'md:grid-cols-5'}`}>
                    <select 
                        value={filterProject} 
                        onChange={(e) => setFilterProject(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Proyecto (Todos)</option>
                        {uniqueProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>

                    {showAnalystFilter && (
                         <select 
                            value={filterAnalyst} 
                            onChange={(e) => setFilterAnalyst(e.target.value)}
                            className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        >
                            <option value="">Analista (Todos)</option>
                            {uniqueAnalysts.map(a => <option key={a} value={a}>{a}</option>)}
                        </select>
                    )}

                    <select 
                        value={filterMacro} 
                        onChange={(e) => setFilterMacro(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Macro (Todos)</option>
                        {uniqueMacros.map(m => <option key={m} value={m}>{m}</option>)}
                    </select>

                    <select 
                        value={filterProcess} 
                        onChange={(e) => setFilterProcess(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Proceso (Todos)</option>
                        {uniqueProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>

                    <select 
                        value={filterDocType} 
                        onChange={(e) => setFilterDocType(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Doc (Todos)</option>
                        {uniqueDocTypes.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>

                    <select 
                        value={filterState} 
                        onChange={(e) => {
                            setFilterState(e.target.value);
                            setQuickFilter('ALL'); // Disable quick filter if manual state is selected
                        }}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        disabled={quickFilter !== 'ALL' && quickFilter !== 'REQUIRED'}
                    >
                        <option value="">Estado (Todos)</option>
                        {Object.keys(STATE_CONFIG).map(key => (
                            <option key={key} value={key}>{STATE_CONFIG[key as DocState].label.split('(')[0]}</option>
                        ))}
                    </select>
                </div>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                        <tr>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('project')}
                            >
                                <div className="flex items-center gap-1">
                                    PROYECTO <SortIcon column="project" />
                                </div>
                            </th>
                            <th className="px-4 py-3">Jerarquía (Macro / Proceso)</th>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('microprocess')}
                            >
                                <div className="flex items-center gap-1">
                                    MICROPROCESO <SortIcon column="microprocess" />
                                </div>
                            </th>
                            <th className="px-4 py-3">Documento</th>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('state')}
                            >
                                <div className="flex items-center gap-1">
                                    Estado Actual <SortIcon column="state" />
                                </div>
                            </th>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('updatedAt')}
                            >
                                <div className="flex items-center gap-1">
                                    Última Actividad <SortIcon column="updatedAt" />
                                </div>
                            </th>
                            {user.role === UserRole.ADMIN && <th className="px-4 py-3 text-right">Admin</th>}
                        </tr>
                    </thead>
                    <tbody>
                        {sortedDocs.length === 0 ? (
                            <tr><td colSpan={7} className="p-8 text-center text-slate-400">No se encontraron documentos con los filtros aplicados.</td></tr>
                        ) : (
                            sortedDocs.map(doc => {
                                const isRequired = isDocRequired(doc);
                                const rowClass = isRequired 
                                    ? "border-b border-slate-50 hover:bg-slate-50 transition-colors" 
                                    : "border-b border-slate-50 bg-slate-100/50 text-slate-400 hover:bg-slate-100 transition-colors";

                                const isNotStarted = doc.state === DocState.NOT_STARTED;

                                return (
                                    <tr key={doc.id} className={rowClass}>
                                        <td className="px-4 py-3 font-bold">
                                            {doc.project}
                                        </td>
                                        <td className="px-4 py-3 text-xs">
                                            <div className="font-medium">{doc.macroprocess}</div>
                                            <div>{doc.process}</div>
                                        </td>
                                        <td className="px-4 py-3 font-medium">
                                            {doc.microprocess || doc.title}
                                            {!isRequired && <div className="text-[10px] text-slate-400 font-normal mt-0.5">(No Requerido)</div>}

                                            {/* VISUALIZACIÓN VERTICAL DE ANALISTAS */}
                                            {showAnalystFilter && doc.assignees && doc.assignees.length > 0 && (
                                                <div className="flex flex-col gap-1 mt-1">
                                                    {doc.assignees.map(aid => {
                                                        const u = allUsers.find(user => user.id === aid);
                                                        return u ? (
                                                            <div key={aid} className="flex items-center gap-1 text-[10px] text-indigo-600">
                                                                <Users size={10} /> {u.name}
                                                            </div>
                                                        ) : null;
                                                    })}
                                                </div>
                                            )}
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex flex-col items-start gap-1">
                                                {doc.docType && (
                                                    <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded border ${
                                                        isRequired 
                                                        ? 'bg-indigo-50 text-indigo-700 border-indigo-100' 
                                                        : 'bg-slate-200 text-slate-500 border-slate-300'
                                                    }`}>
                                                        {doc.docType}
                                                    </span>
                                                )}
                                                <Link to={`/doc/${doc.id}`} className={`text-sm flex items-center hover:underline ${isRequired ? 'text-indigo-600 hover:text-indigo-800' : 'text-slate-500 hover:text-slate-700'}`}>
                                                    {isNotStarted ? 'Iniciar' : 'Ver Detalle'} <ArrowRight size={12} className="ml-1" />
                                                </Link>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex flex-col items-start gap-1">
                                                <span className={`px-2 py-1 rounded-full text-xs font-medium ${STATE_CONFIG[doc.state].color}`}>
                                                    {STATE_CONFIG[doc.state].label.split('(')[0]}
                                                </span>
                                                {!isNotStarted && (
                                                    <span className="text-xs font-mono ml-1">
                                                        Ver: {doc.version} ({doc.progress}%)
                                                    </span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            {doc.updatedAt ? (
                                                <>
                                                    <div className="flex items-center gap-1.5">
                                                        <Calendar size={14} className={isRequired ? "text-slate-400" : "text-slate-300"} />
                                                        <span>{new Date(doc.updatedAt).toLocaleDateString()}</span>
                                                    </div>
                                                    <div className="text-xs pl-5 opacity-70">
                                                        {new Date(doc.updatedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) !== 'Invalid Date' 
                                                            ? new Date(doc.updatedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
                                                            : ''
                                                        }
                                                    </div>
                                                </>
                                            ) : (
                                                <div className="text-xs text-slate-400 italic flex items-center gap-1">
                                                    <Clock size={12} /> Sin actividad
                                                </div>
                                            )}
                                        </td>
                                        {user.role === UserRole.ADMIN && (
                                            <td className="px-4 py-3 text-right">
                                                <button 
                                                    onClick={(e) => handleDeleteDoc(doc.id, e)}
                                                    className="text-slate-400 hover:text-red-600 transition-colors p-1"
                                                    title="Eliminar Documento"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </td>
                                        )}
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>
        </div>

        {/* Chart Column */}
        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 flex flex-col items-center justify-center min-h-[300px]">
                <h2 className="font-semibold text-slate-800 w-full mb-4 text-center">Distribución Requerida</h2>
                {chartData.length > 0 ? (
                    <div className="w-full h-64">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={chartData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={50}
                                    outerRadius={70}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    {chartData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={entry.color} />
                                    ))}
                                </Pie>
                                <Tooltip />
                                <Legend />
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : (
                    <p className="text-slate-400 text-center text-sm px-4">No hay datos requeridos para los filtros seleccionados.</p>
                )}
            </div>

            {/* Quick Summary Box */}
            <div className="bg-indigo-50 rounded-xl p-5 border border-indigo-100">
                <h3 className="font-bold text-indigo-900 mb-2">Resumen</h3>
                <p className="text-sm text-indigo-700 mb-4">
                    Visualizando {filteredDocs.length} documentos totales.
                </p>
                <ul className="text-sm space-y-2 text-indigo-800">
                    <li className="flex justify-between border-b border-indigo-200 pb-1">
                        <span>Total Requeridos:</span>
                        <span className="font-bold">{stats.totalRequired}</span>
                    </li>
                    <li className="flex justify-between border-b border-indigo-200 pb-1">
                        <span>Terminados:</span>
                        <span className="font-bold text-green-600">{stats.finished}</span>
                    </li>
                    <li className="flex justify-between text-xs pt-1 opacity-80">
                        <span>No Requeridos:</span>
                        <span>{filteredDocs.length - filteredDocs.filter(d => isDocRequired(d)).length}</span>
                    </li>
                </ul>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div 
        onClick={onClick}
        className={`bg-white p-3 rounded-xl shadow-sm border transition-all cursor-pointer flex items-center space-x-3 hover:shadow-md select-none
        ${isActive ? 'border-indigo-500 ring-2 ring-indigo-200 bg-indigo-50/20' : 'border-slate-200 hover:border-indigo-300'}`}
    >
        <div className={`p-2 rounded-lg ${color}`}>
            <Icon size={20} />
        </div>
        <div>
            <p className="text-slate-500 text-[10px] font-bold uppercase leading-tight">{title}</p>
            <p className={`text-xl font-bold leading-tight ${isActive ? 'text-indigo-700' : 'text-slate-900'}`}>{value}</p>
        </div>
    </div>
);

export default Dashboard;

import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { DocumentService, HierarchyService, UserService } from '../services/firebaseBackend';
import { Document, User, UserRole, DocState, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { Plus, FileText, Clock, CheckCircle, AlertTriangle, Filter, Trash2, Users, Search, X, Calendar, Inbox, ArrowRight, Activity, BookOpen, UserCheck, ShieldCheck, ArrowUp, ArrowDown, ArrowUpDown, PauseCircle } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface DashboardProps {
  user: User;
}

type SortKey = 'project' | 'microprocess' | 'state' | 'updatedAt';
type QuickFilterType = 'ALL' | 'REQUIRED' | 'NOT_STARTED' | 'IN_PROCESS' | 'REFERENT' | 'CONTROL' | 'FINISHED';

const Dashboard: React.FC<DashboardProps> = ({ user }) => {
  const [docs, setDocs] = useState<Document[]>([]);
  const [requiredMap, setRequiredMap] = useState<Record<string, DocType[]>>({});
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  // Filter States
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterDocType, setFilterDocType] = useState('');
  const [filterState, setFilterState] = useState('');
  const [filterAnalyst, setFilterAnalyst] = useState('');

  // Quick Filter State (Stat Cards)
  const [quickFilter, setQuickFilter] = useState<QuickFilterType>('ALL');

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'updatedAt',
    direction: 'desc' // Default: Newest first
  });

  useEffect(() => {
    loadData();
  }, []);

  // Helper to compare versions robustly
  const isVersionNewer = (v1: string, v2: string): boolean => {
      if (!v1) return false;
      if (!v2) return true;
      if (v1 === '-') return false; // Not Started is always older

      // Clean versions (remove 'v', 'AR', 'ACG')
      const cleanV1 = v1.replace(/[^0-9.]/g, '');
      const cleanV2 = v2.replace(/[^0-9.]/g, '');

      const parts1 = cleanV1.split('.').map(Number);
      const parts2 = cleanV2.split('.').map(Number);

      for (let i = 0; i < Math.max(parts1.length, parts2.length); i++) {
          const num1 = parts1[i] || 0;
          const num2 = parts2[i] || 0;
          if (num1 > num2) return true;
          if (num1 < num2) return false;
      }

      // If numbers are equal, check specific suffixes for priority
      // Priority: ACG > AR > (none)
      const weight1 = v1.includes('ACG') ? 3 : v1.includes('AR') ? 2 : 1;
      const weight2 = v2.includes('ACG') ? 3 : v2.includes('AR') ? 2 : 1;

      return weight1 > weight2;
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [data, reqs, users] = await Promise.all([
            DocumentService.getAll(),
            HierarchyService.getRequiredTypesMap(),
            UserService.getAll()
        ]);

        // DEDUPLICATION LOGIC (Show only latest version)
        // Group by Project + Microprocess + DocType
        const latestDocsMap = new Map<string, Document>();

        data.forEach(doc => {
            const uniqueKey = `${doc.project || 'Gen'}|${doc.microprocess || doc.title}|${doc.docType || 'Gen'}`;
            const existing = latestDocsMap.get(uniqueKey);

            // Logic: Determine which is the "Current Active" document
            let shouldUseNew = false;

            if (!existing) {
                shouldUseNew = true;
            } else {
                const timeNew = doc.updatedAt ? new Date(doc.updatedAt).getTime() : 0;
                const timeExisting = existing.updatedAt ? new Date(existing.updatedAt).getTime() : 0;

                // 1. Primary check: Date
                if (timeNew > timeExisting) {
                    shouldUseNew = true;
                } 
                // 2. Secondary check: If dates are effectively equal (common in bulk imports), use Version
                else if (timeNew === timeExisting) {
                    if (isVersionNewer(doc.version, existing.version)) {
                        shouldUseNew = true;
                    }
                }
            }

            if (shouldUseNew) {
                latestDocsMap.set(uniqueKey, doc);
            }
        });

        const finalDocs = Array.from(latestDocsMap.values());

        setDocs(finalDocs);
        setRequiredMap(reqs);
        setAllUsers(users);
    } catch (error) {
        console.error("Error loading dashboard data:", error);
    } finally {
        setLoading(false);
    }
  };

  const handleDeleteDoc = async (id: string, e: React.MouseEvent) => {
    e.preventDefault(); // Prevent navigation
    if (!window.confirm('¿Eliminar este documento permanentemente?')) return;
    await DocumentService.delete(id);
    await loadData();
  };

  // Helper to determine if a doc is strictly required
  const isDocRequired = (doc: Document): boolean => {
      const key = `${doc.project}|${doc.microprocess}`;
      const requiredTypes = requiredMap[key];
      if (!requiredTypes) return false; 
      return doc.docType ? requiredTypes.includes(doc.docType) : false;
  };

  // Helper to get formatted assignees names (returns array of names for display filtering)
  const getAssigneesNames = (doc: Document): string[] => {
      if (!doc.assignees || doc.assignees.length === 0) return [doc.authorName]; 
      return doc.assignees
          .map(id => allUsers.find(u => u.id === id)?.name)
          .filter((name): name is string => !!name);
  };

  const handleQuickFilterClick = (type: QuickFilterType) => {
      if (quickFilter === type) {
          setQuickFilter('ALL'); // Toggle off
      } else {
          setQuickFilter(type);
          setFilterState(''); // Reset manual state dropdown to avoid conflicts
      }
  };

  const getFilteredDocs = () => {
    let filtered = docs;

    // 2. Explicit Filters
    if (filterProject) {
        filtered = filtered.filter(d => d.project === filterProject);
    }
    if (filterMacro) {
        filtered = filtered.filter(d => d.macroprocess === filterMacro);
    }
    if (filterProcess) {
        filtered = filtered.filter(d => d.process === filterProcess);
    }
    if (filterDocType) {
        filtered = filtered.filter(d => d.docType === filterDocType);
    }
    if (filterState) {
        filtered = filtered.filter(d => d.state === filterState);
    }
    if (filterAnalyst) {
        filtered = filtered.filter(d => {
            const names = getAssigneesNames(d);
            // Check if ANY of the assignees matches the filter
            return names.includes(filterAnalyst);
        });
    }

    // 3. Quick Filters (Stat Cards)
    if (quickFilter !== 'ALL') {
        // All quick filters (except ALL) imply showing "Required" docs context
        filtered = filtered.filter(d => isDocRequired(d));

        switch (quickFilter) {
            case 'NOT_STARTED':
                filtered = filtered.filter(d => d.state === DocState.NOT_STARTED);
                break;
            case 'IN_PROCESS':
                filtered = filtered.filter(d => 
                    // Excluye NOT_STARTED, ya tiene su propia tarjeta
                    d.state === DocState.INITIATED || 
                    d.state === DocState.IN_PROCESS || 
                    d.state === DocState.INTERNAL_REVIEW
                );
                break;
            case 'REFERENT':
                filtered = filtered.filter(d => 
                    d.state === DocState.SENT_TO_REFERENT || 
                    d.state === DocState.REFERENT_REVIEW
                );
                break;
            case 'CONTROL':
                filtered = filtered.filter(d => 
                    d.state === DocState.SENT_TO_CONTROL || 
                    d.state === DocState.CONTROL_REVIEW
                );
                break;
            case 'FINISHED':
                filtered = filtered.filter(d => d.state === DocState.APPROVED);
                break;
            case 'REQUIRED':
                // Already filtered by isDocRequired above
                break;
        }
    }

    return filtered;
  };

  // Sorting Logic
  const handleSort = (key: SortKey) => {
      let direction: 'asc' | 'desc' = 'asc';
      if (sortConfig.key === key && sortConfig.direction === 'asc') {
          direction = 'desc';
      }
      setSortConfig({ key, direction });
  };

  const getSortedDocs = (filtered: Document[]) => {
      return [...filtered].sort((a, b) => {
          const modifier = sortConfig.direction === 'asc' ? 1 : -1;

          switch (sortConfig.key) {
              case 'updatedAt':
                  const timeA = a.updatedAt ? new Date(a.updatedAt).getTime() : 0;
                  const timeB = b.updatedAt ? new Date(b.updatedAt).getTime() : 0;
                  return (timeA - timeB) * modifier;
              case 'project':
                  return (a.project || '').localeCompare(b.project || '') * modifier;
              case 'microprocess':
                  const nameA = a.microprocess || a.title;
                  const nameB = b.microprocess || b.title;
                  return nameA.localeCompare(nameB) * modifier;
              case 'state':
                   return (a.progress - b.progress) * modifier;
              default:
                  return 0;
          }
      });
  };

  const filteredDocs = getFilteredDocs();
  const sortedDocs = getSortedDocs(filteredDocs);

  // Extract unique values for dropdowns from the FULL deduplicated list
  const baseDocs = docs;

  const uniqueProjects = Array.from(new Set(baseDocs.map(d => d.project).filter(Boolean))) as string[];

  const uniqueMacros = Array.from(new Set(
      baseDocs.filter(d => !filterProject || d.project === filterProject)
      .map(d => d.macroprocess).filter(Boolean)
  )) as string[];

  const uniqueProcesses = Array.from(new Set(
      baseDocs.filter(d => (!filterProject || d.project === filterProject) && (!filterMacro || d.macroprocess === filterMacro))
      .map(d => d.process).filter(Boolean)
  )) as string[];

  const uniqueDocTypes = Array.from(new Set(
      baseDocs.filter(d => 
        (!filterProject || d.project === filterProject) && 
        (!filterMacro || d.macroprocess === filterMacro) &&
        (!filterProcess || d.process === filterProcess)
      )
      .map(d => d.docType).filter(Boolean)
  )) as string[];

  // Flattened list of individual analysts
  const uniqueAnalysts = Array.from(new Set(
      baseDocs.filter(d => 
        (!filterProject || d.project === filterProject) && 
        (!filterMacro || d.macroprocess === filterMacro)
      )
      .flatMap(d => getAssigneesNames(d))
  )).sort() as string[];

  // Calculate Stats based on BASE filtered documents (ignoring quick filter for the counts themselves to stay static relative to dropdowns)
  const contextDocs = (() => {
      let d = docs;
      if (filterProject) d = d.filter(doc => doc.project === filterProject);
      if (filterMacro) d = d.filter(doc => doc.macroprocess === filterMacro);
      if (filterProcess) d = d.filter(doc => doc.process === filterProcess);
      if (filterDocType) d = d.filter(doc => doc.docType === filterDocType);
      if (filterAnalyst) d = d.filter(doc => getAssigneesNames(doc).includes(filterAnalyst));
      return d.filter(doc => isDocRequired(doc));
  })();

  const stats = {
    totalRequired: contextDocs.length,
    notStarted: contextDocs.filter(d => d.state === DocState.NOT_STARTED).length,
    inProcess: contextDocs.filter(d => 
        d.state === DocState.INITIATED || 
        d.state === DocState.IN_PROCESS || 
        d.state === DocState.INTERNAL_REVIEW
    ).length,
    referent: contextDocs.filter(d => 
        d.state === DocState.SENT_TO_REFERENT || 
        d.state === DocState.REFERENT_REVIEW
    ).length,
    control: contextDocs.filter(d => 
        d.state === DocState.SENT_TO_CONTROL || 
        d.state === DocState.CONTROL_REVIEW
    ).length,
    finished: contextDocs.filter(d => d.state === DocState.APPROVED).length
  };

  const chartData = [
    { name: 'No Iniciado', value: stats.notStarted, color: '#cbd5e1' },
    { name: 'En Proceso', value: stats.inProcess, color: '#3b82f6' },
    { name: 'Referente', value: stats.referent, color: '#a855f7' },
    { name: 'Control Gestión', value: stats.control, color: '#f97316' },
    { name: 'Terminados', value: stats.finished, color: '#22c55e' },
  ].filter(d => d.value > 0);

  const clearFilters = () => {
      setFilterProject('');
      setFilterMacro('');
      setFilterProcess('');
      setFilterDocType('');
      setFilterState('');
      setFilterAnalyst('');
      setQuickFilter('ALL');
  };

  const hasFilters = filterProject || filterMacro || filterProcess || filterDocType || filterState || filterAnalyst || quickFilter !== 'ALL';

  const SortIcon = ({ column }: { column: SortKey }) => {
      if (sortConfig.key !== column) return <ArrowUpDown size={14} className="text-slate-300 opacity-0 group-hover:opacity-100 transition-opacity" />;
      return sortConfig.direction === 'asc' 
        ? <ArrowUp size={14} className="text-indigo-600" /> 
        : <ArrowDown size={14} className="text-indigo-600" />;
  };

  // Show analyst filter for everyone now, as everyone can see everything
  const showAnalystFilter = true; 

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando dashboard...</div>;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-900">Dashboard</h1>
            <p className="text-slate-500">Vista general</p>
        </div>
        <div className="flex gap-2">
            {user.role === UserRole.ADMIN && (
                <Link to="/admin/users" className="inline-flex items-center justify-center px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors shadow-sm">
                    <Users size={18} className="mr-2" />
                    Gestionar Usuarios
                </Link>
            )}
            {user.role === UserRole.ANALYST && (
                <Link to="/new" className="inline-flex items-center justify-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm">
                    <Plus size={18} className="mr-2" />
                    Nueva Solicitud
                </Link>
            )}
        </div>
      </div>

      {/* Stats Cards - Interactive */}
      <div className="grid grid-cols-1 md:grid-cols-6 gap-3">
        <StatCard 
            title="Doc. Requeridos" 
            value={stats.totalRequired} 
            icon={BookOpen} 
            color="bg-slate-100 text-slate-600" 
            isActive={quickFilter === 'REQUIRED'}
            onClick={() => handleQuickFilterClick('REQUIRED')}
        />
        <StatCard 
            title="No Iniciado" 
            value={stats.notStarted} 
            icon={Clock} 
            color="bg-slate-50 text-slate-400 border-slate-200" 
            isActive={quickFilter === 'NOT_STARTED'}
            onClick={() => handleQuickFilterClick('NOT_STARTED')}
        />
        <StatCard 
            title="En Proceso" 
            value={stats.inProcess} 
            icon={Activity} 
            color="bg-blue-100 text-blue-600" 
            isActive={quickFilter === 'IN_PROCESS'}
            onClick={() => handleQuickFilterClick('IN_PROCESS')}
        />
        <StatCard 
            title="Referente" 
            value={stats.referent} 
            icon={Users} 
            color="bg-purple-100 text-purple-600" 
            isActive={quickFilter === 'REFERENT'}
            onClick={() => handleQuickFilterClick('REFERENT')}
        />
        <StatCard 
            title="Control Gestión" 
            value={stats.control} 
            icon={ShieldCheck} 
            color="bg-orange-100 text-orange-600" 
            isActive={quickFilter === 'CONTROL'}
            onClick={() => handleQuickFilterClick('CONTROL')}
        />
        <StatCard 
            title="Terminados" 
            value={stats.finished} 
            icon={CheckCircle} 
            color="bg-green-100 text-green-600" 
            isActive={quickFilter === 'FINISHED'}
            onClick={() => handleQuickFilterClick('FINISHED')}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Document List (Takes up 3 columns) */}
        <div className="lg:col-span-3 bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">

            {/* Filter Bar */}
            <div className="p-4 border-b border-slate-100 bg-slate-50/50">
                <div className="flex items-center justify-between mb-3">
                    <h2 className="font-semibold text-slate-800 flex items-center gap-2">
                        <Filter size={18} className="text-indigo-600" />
                        Todos los Documentos
                    </h2>
                    {hasFilters && (
                        <button onClick={clearFilters} className="text-xs text-red-500 flex items-center gap-1 hover:underline">
                            <X size={14} /> Limpiar filtros
                        </button>
                    )}
                </div>

                {quickFilter !== 'ALL' && (
                    <div className="mb-3 px-3 py-2 bg-indigo-50 border border-indigo-100 rounded-lg text-sm text-indigo-700 flex items-center justify-between">
                        <span>
                            Filtrando por: <strong>
                                {quickFilter === 'REQUIRED' && 'Total Requeridos'}
                                {quickFilter === 'NOT_STARTED' && 'No Iniciados'}
                                {quickFilter === 'IN_PROCESS' && 'En Proceso'}
                                {quickFilter === 'REFERENT' && 'En Referente'}
                                {quickFilter === 'CONTROL' && 'Control de Gestión'}
                                {quickFilter === 'FINISHED' && 'Terminados'}
                            </strong>
                        </span>
                        <button onClick={() => setQuickFilter('ALL')} className="text-indigo-500 hover:text-indigo-800"><X size={16}/></button>
                    </div>
                )}

                <div className={`grid grid-cols-1 gap-3 ${showAnalystFilter ? 'md:grid-cols-6' : 'md:grid-cols-5'}`}>
                    <select 
                        value={filterProject} 
                        onChange={(e) => setFilterProject(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Proyecto (Todos)</option>
                        {uniqueProjects.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>

                    {showAnalystFilter && (
                         <select 
                            value={filterAnalyst} 
                            onChange={(e) => setFilterAnalyst(e.target.value)}
                            className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        >
                            <option value="">Analista (Todos)</option>
                            {uniqueAnalysts.map(a => <option key={a} value={a}>{a}</option>)}
                        </select>
                    )}

                    <select 
                        value={filterMacro} 
                        onChange={(e) => setFilterMacro(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Macro (Todos)</option>
                        {uniqueMacros.map(m => <option key={m} value={m}>{m}</option>)}
                    </select>

                    <select 
                        value={filterProcess} 
                        onChange={(e) => setFilterProcess(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Proceso (Todos)</option>
                        {uniqueProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>

                    <select 
                        value={filterDocType} 
                        onChange={(e) => setFilterDocType(e.target.value)}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    >
                        <option value="">Doc (Todos)</option>
                        {uniqueDocTypes.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>

                    <select 
                        value={filterState} 
                        onChange={(e) => {
                            setFilterState(e.target.value);
                            setQuickFilter('ALL'); // Disable quick filter if manual state is selected
                        }}
                        className="text-sm p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                        disabled={quickFilter !== 'ALL' && quickFilter !== 'REQUIRED'}
                    >
                        <option value="">Estado (Todos)</option>
                        {Object.keys(STATE_CONFIG).map(key => (
                            <option key={key} value={key}>{STATE_CONFIG[key as DocState].label.split('(')[0]}</option>
                        ))}
                    </select>
                </div>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                        <tr>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('project')}
                            >
                                <div className="flex items-center gap-1">
                                    PROYECTO <SortIcon column="project" />
                                </div>
                            </th>
                            <th className="px-4 py-3">Jerarquía (Macro / Proceso)</th>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('microprocess')}
                            >
                                <div className="flex items-center gap-1">
                                    MICROPROCESO <SortIcon column="microprocess" />
                                </div>
                            </th>
                            <th className="px-4 py-3">Documento</th>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('state')}
                            >
                                <div className="flex items-center gap-1">
                                    Estado Actual <SortIcon column="state" />
                                </div>
                            </th>
                            <th 
                                className="px-4 py-3 cursor-pointer hover:bg-slate-100 group select-none"
                                onClick={() => handleSort('updatedAt')}
                            >
                                <div className="flex items-center gap-1">
                                    Última Actividad <SortIcon column="updatedAt" />
                                </div>
                            </th>
                            {user.role === UserRole.ADMIN && <th className="px-4 py-3 text-right">Admin</th>}
                        </tr>
                    </thead>
                    <tbody>
                        {sortedDocs.length === 0 ? (
                            <tr><td colSpan={7} className="p-8 text-center text-slate-400">No se encontraron documentos con los filtros aplicados.</td></tr>
                        ) : (
                            sortedDocs.map(doc => {
                                const isRequired = isDocRequired(doc);
                                const rowClass = isRequired 
                                    ? "border-b border-slate-50 hover:bg-slate-50 transition-colors" 
                                    : "border-b border-slate-50 bg-slate-100/50 text-slate-400 hover:bg-slate-100 transition-colors";

                                const isNotStarted = doc.state === DocState.NOT_STARTED;

                                return (
                                    <tr key={doc.id} className={rowClass}>
                                        <td className="px-4 py-3 font-bold">
                                            {doc.project}
                                        </td>
                                        <td className="px-4 py-3 text-xs">
                                            <div className="font-medium">{doc.macroprocess}</div>
                                            <div>{doc.process}</div>
                                        </td>
                                        <td className="px-4 py-3 font-medium">
                                            {doc.microprocess || doc.title}
                                            {!isRequired && <div className="text-[10px] text-slate-400 font-normal mt-0.5">(No Requerido)</div>}

                                            {/* VISUALIZACIÓN VERTICAL DE ANALISTAS */}
                                            {showAnalystFilter && doc.assignees && doc.assignees.length > 0 && (
                                                <div className="flex flex-col gap-1 mt-1">
                                                    {doc.assignees.map(aid => {
                                                        const u = allUsers.find(user => user.id === aid);
                                                        return u ? (
                                                            <div key={aid} className="flex items-center gap-1 text-[10px] text-indigo-600">
                                                                <Users size={10} /> {u.name}
                                                            </div>
                                                        ) : null;
                                                    })}
                                                </div>
                                            )}
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex flex-col items-start gap-1">
                                                {doc.docType && (
                                                    <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded border ${
                                                        isRequired 
                                                        ? 'bg-indigo-50 text-indigo-700 border-indigo-100' 
                                                        : 'bg-slate-200 text-slate-500 border-slate-300'
                                                    }`}>
                                                        {doc.docType}
                                                    </span>
                                                )}
                                                <Link to={`/doc/${doc.id}`} className={`text-sm flex items-center hover:underline ${isRequired ? 'text-indigo-600 hover:text-indigo-800' : 'text-slate-500 hover:text-slate-700'}`}>
                                                    {isNotStarted ? 'Iniciar' : 'Ver Detalle'} <ArrowRight size={12} className="ml-1" />
                                                </Link>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex flex-col items-start gap-1">
                                                <span className={`px-2 py-1 rounded-full text-xs font-medium ${STATE_CONFIG[doc.state].color}`}>
                                                    {STATE_CONFIG[doc.state].label.split('(')[0]}
                                                </span>
                                                {!isNotStarted && (
                                                    <span className="text-xs font-mono ml-1">
                                                        Ver: {doc.version} ({doc.progress}%)
                                                    </span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            {doc.updatedAt ? (
                                                <>
                                                    <div className="flex items-center gap-1.5">
                                                        <Calendar size={14} className={isRequired ? "text-slate-400" : "text-slate-300"} />
                                                        <span>{new Date(doc.updatedAt).toLocaleDateString()}</span>
                                                    </div>
                                                    <div className="text-xs pl-5 opacity-70">
                                                        {new Date(doc.updatedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) !== 'Invalid Date' 
                                                            ? new Date(doc.updatedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
                                                            : ''
                                                        }
                                                    </div>
                                                </>
                                            ) : (
                                                <div className="text-xs text-slate-400 italic flex items-center gap-1">
                                                    <Clock size={12} /> Sin actividad
                                                </div>
                                            )}
                                        </td>
                                        {user.role === UserRole.ADMIN && (
                                            <td className="px-4 py-3 text-right">
                                                <button 
                                                    onClick={(e) => handleDeleteDoc(doc.id, e)}
                                                    className="text-slate-400 hover:text-red-600 transition-colors p-1"
                                                    title="Eliminar Documento"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </td>
                                        )}
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>
        </div>

        {/* Chart Column */}
        <div className="lg:col-span-1 space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 flex flex-col items-center justify-center min-h-[300px]">
                <h2 className="font-semibold text-slate-800 w-full mb-4 text-center">Distribución Requerida</h2>
                {chartData.length > 0 ? (
                    <div className="w-full h-64">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart>
                                <Pie
                                    data={chartData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={50}
                                    outerRadius={70}
                                    paddingAngle={5}
                                    dataKey="value"
                                >
                                    {chartData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={entry.color} />
                                    ))}
                                </Pie>
                                <Tooltip />
                                <Legend />
                            </PieChart>
                        </ResponsiveContainer>
                    </div>
                ) : (
                    <p className="text-slate-400 text-center text-sm px-4">No hay datos requeridos para los filtros seleccionados.</p>
                )}
            </div>

            {/* Quick Summary Box */}
            <div className="bg-indigo-50 rounded-xl p-5 border border-indigo-100">
                <h3 className="font-bold text-indigo-900 mb-2">Resumen</h3>
                <p className="text-sm text-indigo-700 mb-4">
                    Visualizando {filteredDocs.length} documentos totales.
                </p>
                <ul className="text-sm space-y-2 text-indigo-800">
                    <li className="flex justify-between border-b border-indigo-200 pb-1">
                        <span>Total Requeridos:</span>
                        <span className="font-bold">{stats.totalRequired}</span>
                    </li>
                    <li className="flex justify-between border-b border-indigo-200 pb-1">
                        <span>No Iniciados:</span>
                        <span className="font-bold text-slate-500">{stats.notStarted}</span>
                    </li>
                    <li className="flex justify-between border-b border-indigo-200 pb-1">
                        <span>Terminados:</span>
                        <span className="font-bold text-green-600">{stats.finished}</span>
                    </li>
                    <li className="flex justify-between text-xs pt-1 opacity-80">
                        <span>No Requeridos:</span>
                        <span>{filteredDocs.length - filteredDocs.filter(d => isDocRequired(d)).length}</span>
                    </li>
                </ul>
            </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon: Icon, color, isActive, onClick }: any) => (
    <div 
        onClick={onClick}
        className={`bg-white p-3 rounded-xl shadow-sm border transition-all cursor-pointer flex items-center space-x-3 hover:shadow-md select-none
        ${isActive ? 'border-indigo-500 ring-2 ring-indigo-200 bg-indigo-50/20' : 'border-slate-200 hover:border-indigo-300'}`}
    >
        <div className={`p-2 rounded-lg ${color}`}>
            <Icon size={20} />
        </div>
        <div>
            <p className="text-slate-500 text-[10px] font-bold uppercase leading-tight">{title}</p>
            <p className={`text-xl font-bold leading-tight ${isActive ? 'text-indigo-700' : 'text-slate-900'}`}>{value}</p>
        </div>
    </div>
);

export default Dashboard;

